-- filename: definitions/cleansed/daily_warranty_claims.sqlx

-- This config block defines the table as an incremental table.
-- Dataform will create the table on the first run and append new data on subsequent runs.
config {
  type: "incremental",
  schema: "warranty_data",
  name: "daily_warranty_claims",
  description: "Cleansed and validated warranty claims data, updated incrementally each day. Contains data quality checks.",
  tags: ["daily", "cleansed", "warranty"]
}

/*
 PRE-OPERATIONS: Data Validation on Source Data
 These operations run BEFORE the main query. They validate the new batch of source data
 before it gets inserted into the target table. If an assertion fails, the entire run fails,
 preventing bad data from being loaded.
 These assertions are written using BigQuery scripting syntax.
*/
pre_operations {
  -- Assertion 1: Check for negative repair costs in the new data.
  ${
    when(
      incremental(),
      -- On incremental runs, only check rows newer than the last record in the target table.
      `
      ASSERT (
        SELECT COUNT(*) FROM ${ref("warranty_claims")}
        WHERE SAFE_CAST(repair_cost AS NUMERIC) < 0
        AND SAFE_CAST(claim_date AS DATE) > (SELECT MAX(claim_date) FROM ${self()})
      ) = 0
      OPTIONS(description="New warranty claims must not have a negative repair_cost.");
      `,
      -- On a full refresh, check all rows in the source.
      `
      ASSERT (
        SELECT COUNT(*) FROM ${ref("warranty_claims")}
        WHERE SAFE_CAST(repair_cost AS NUMERIC) < 0
      ) = 0
      OPTIONS(description="Warranty claims must not have a negative repair_cost.");
      `
    )
  }

  -- Assertion 2: Check for NULL or 'NA' mileage values in the new data.
  ${
    when(
      incremental(),
      `
      ASSERT (
        SELECT COUNT(*) FROM ${ref("warranty_claims")}
        WHERE mileage IS NULL OR mileage = 'NA'
        AND SAFE_CAST(claim_date AS DATE) > (SELECT MAX(claim_date) FROM ${self()})
      ) = 0
      OPTIONS(description="New warranty claims must have a valid mileage value.");
      `,
      `
      ASSERT (
        SELECT COUNT(*) FROM ${ref("warranty_claims")}
        WHERE mileage IS NULL OR mileage = 'NA'
      ) = 0
      OPTIONS(description="Warranty claims must have a valid mileage value.");
      `
    )
  }
}

/*
 MAIN QUERY: Select, Clean, and Append New Records
 This is the core logic for the incremental table.
 - It selects from the source table (defined from 'warranty_claims.csv').
 - It cleans the data by casting to correct types and handling 'NA' values.
 - The "when(incremental(), ...)" clause filters for new records based on the claim_date.
*/
SELECT
  SAFE_CAST(claim_id AS INT64) AS claim_id,
  model,
  dealer,
  -- Replace string 'NA' with a true NULL before casting to an integer
  SAFE_CAST(NULLIF(mileage, 'NA') AS INT64) AS mileage,
  SAFE_CAST(repair_cost AS NUMERIC) AS repair_cost,
  failure_code,
  SAFE_CAST(claim_date AS DATE) AS claim_date
FROM
  -- This ref() function points to the source table defined from the CSV
  ${ref("warranty_claims")}

-- This is the crucial part for an incremental table. On subsequent runs,
-- it only selects records with a claim_date later than the most recent one
-- already in this table.
${when(incremental(), `WHERE SAFE_CAST(claim_date AS DATE) > (SELECT MAX(claim_date) FROM ${self()})`)}


/*
 POST-OPERATION: Data Validation on Target Table
 This operation runs AFTER new data has been inserted into the table.
 It's used here to ensure the final table maintains its integrity constraints,
 such as primary key uniqueness.
*/
post_operations {
  -- Assertion: Verify that claim_id is unique across the entire table after the insert.
  ASSERT (
    SELECT COUNT(*) FROM (
      SELECT
        claim_id
      FROM ${self()}
      GROUP BY
        claim_id
      HAVING
        COUNT(*) > 1
    )
  ) = 0
  OPTIONS(description="The claim_id in the final warranty claims table must be unique.");
}

