The following is a complete React component, `WarrantyClaims`, that displays warranty claims data in a table. It includes functionality for sorting by any column and filtering by claim status. The component is built using functional components and React Hooks (`useState`, `useMemo`).

The solution is divided into two parts:
1.  **`WarrantyClaims.jsx`**: The React component file.
2.  **`WarrantyClaims.css`**: The CSS file for styling the component.

### 1. React Component: `WarrantyClaims.jsx`

This file contains the component logic, including state management for sorting and filtering, and the JSX for rendering the UI.

```jsx
import React, { useState, useMemo } from 'react';
import './WarrantyClaims.css';

// Mock data representing warranty claims. In a real application, this would come from an API.
const mockClaimsData = [
  { id: 101, productName: 'Quantum Laptop Pro', claimDate: '2023-11-20', status: 'Pending' },
  { id: 102, productName: 'Nebula Smartphone', claimDate: '2023-10-15', status: 'Approved' },
  { id: 103, productName: 'Vortex VR Headset', claimDate: '2023-11-05', status: 'Rejected' },
  { id: 104, productName: 'Quantum Laptop Pro', claimDate: '2023-11-22', status: 'Approved' },
  { id: 105, productName: 'Orion Tablet', claimDate: '2023-09-30', status: 'Approved' },
  { id: 106, productName: 'Nebula Smartphone', claimDate: '2023-12-01', status: 'Pending' },
  { id: 107, productName: 'Galaxy Smartwatch', claimDate: '2023-08-12', status: 'Rejected' },
  { id: 108, productName: 'Orion Tablet', claimDate: '2023-11-18', status: 'Pending' },
];

/**
 * A custom hook to manage sorting and filtering logic for the claims data.
 * This encapsulates the logic and makes the main component cleaner.
 */
const useClaimsProcessor = (claims) => {
  const [sortConfig, setSortConfig] = useState({ key: 'claimDate', direction: 'descending' });
  const [filterStatus, setFilterStatus] = useState('All');

  const processedClaims = useMemo(() => {
    let filteredItems = [...claims];

    // Apply filtering
    if (filterStatus !== 'All') {
      filteredItems = filteredItems.filter(
        (claim) => claim.status === filterStatus
      );
    }

    // Apply sorting
    if (sortConfig.key) {
      filteredItems.sort((a, b) => {
        const aValue = a[sortConfig.key];
        const bValue = b[sortConfig.key];

        // Handle date comparison
        if (sortConfig.key === 'claimDate') {
            if (new Date(aValue) < new Date(bValue)) {
                return sortConfig.direction === 'ascending' ? -1 : 1;
            }
            if (new Date(aValue) > new Date(bValue)) {
                return sortConfig.direction === 'ascending' ? 1 : -1;
            }
            return 0;
        }

        // Handle string/number comparison
        if (aValue < bValue) {
          return sortConfig.direction === 'ascending' ? -1 : 1;
        }
        if (aValue > bValue) {
          return sortConfig.direction === 'ascending' ? 1 : -1;
        }
        return 0;
      });
    }

    return filteredItems;
  }, [claims, sortConfig, filterStatus]);

  const requestSort = (key) => {
    let direction = 'ascending';
    if (sortConfig.key === key && sortConfig.direction === 'ascending') {
      direction = 'descending';
    }
    setSortConfig({ key, direction });
  };

  const getSortIndicator = (columnKey) => {
    if (sortConfig.key !== columnKey) return null;
    return sortConfig.direction === 'ascending' ? ' ▲' : ' ▼';
  };

  return { 
    processedClaims, 
    requestSort, 
    setFilterStatus, 
    filterStatus, 
    getSortIndicator 
  };
};


const WarrantyClaims = () => {
  const { 
    processedClaims, 
    requestSort, 
    setFilterStatus, 
    filterStatus,
    getSortIndicator 
  } = useClaimsProcessor(mockClaimsData);

  // Get unique statuses for the filter dropdown, including 'All'
  const uniqueStatuses = ['All', ...new Set(mockClaimsData.map(claim => claim.status))];

  return (
    <div className="claims-container">
      <h1>Warranty Claims</h1>

      <div className="controls">
        <label htmlFor="status-filter">Filter by Status:</label>
        <select
          id="status-filter"
          value={filterStatus}
          onChange={(e) => setFilterStatus(e.target.value)}
        >
          {uniqueStatuses.map(status => (
            <option key={status} value={status}>{status}</option>
          ))}
        </select>
      </div>

      <table className="claims-table">
        <thead>
          <tr>
            <th onClick={() => requestSort('id')}>ID{getSortIndicator('id')}</th>
            <th onClick={() => requestSort('productName')}>Product Name{getSortIndicator('productName')}</th>
            <th onClick={() => requestSort('claimDate')}>Claim Date{getSortIndicator('claimDate')}</th>
            <th onClick={() => requestSort('status')}>Status{getSortIndicator('status')}</th>
          </tr>
        </thead>
        <tbody>
          {processedClaims.length > 0 ? (
            processedClaims.map((claim) => (
              <tr key={claim.id}>
                <td>{claim.id}</td>
                <td>{claim.productName}</td>
                <td>{new Date(claim.claimDate).toLocaleDateString()}</td>
                <td>
                  <span className={`status-pill status-${claim.status.toLowerCase()}`}>
                    {claim.status}
                  </span>
                </td>
              </tr>
            ))
          ) : (
            <tr>
              <td colSpan="4">No claims match the current filter.</td>
            </tr>
          )}
        </tbody>
      </table>
    </div>
  );
};

export default WarrantyClaims;
```

