This file contains the logic for initializing the charts with mock data and handling the interactive filtering for the sales chart.

```javascript
document.addEventListener('DOMContentLoaded', () => {

    // --- MOCK DATA ---
    const salesData = {
        monthly: {
            labels: ['Jan', 'Feb', 'Mar', 'Apr', 'May', 'Jun', 'Jul'],
            data: [65000, 59000, 80000, 81000, 56000, 55000, 90000]
        },
        quarterly: {
            labels: ['Q1', 'Q2', 'Q3', 'Q4'],
            data: [204000, 192000, 250000, 220000]
        },
        yearly: {
            labels: ['2020', '2021', '2022', '2023'],
            data: [750000, 820000, 910000, 890000]
        }
    };

    const warrantyData = {
        labels: ['Standard', 'Extended', 'Premium', 'Expired'],
        data: [45, 25, 15, 15]
    };

    // --- SALES TRENDS CHART (Line) ---
    const salesCtx = document.getElementById('salesChart').getContext('2d');
    const salesChart = new Chart(salesCtx, {
        type: 'line',
        data: {
            labels: salesData.monthly.labels,
            datasets: [{
                label: 'Sales ($)',
                data: salesData.monthly.data,
                backgroundColor: 'rgba(0, 123, 255, 0.1)',
                borderColor: 'rgba(0, 123, 255, 1)',
                borderWidth: 2,
                tension: 0.4, // Makes the line curved
                fill: true
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
            scales: {
                y: {
                    beginAtZero: true
                }
            }
        }
    });

    // --- WARRANTY DISTRIBUTION CHART (Doughnut) ---
    const warrantyCtx = document.getElementById('warrantyChart').getContext('2d');
    const warrantyChart = new Chart(warrantyCtx, {
        type: 'doughnut',
        data: {
            labels: warrantyData.labels,
            datasets: [{
                label: 'Warranty Distribution',
                data: warrantyData.data,
                backgroundColor: [
                    'rgba(0, 123, 255, 0.7)',
                    'rgba(23, 162, 184, 0.7)',
                    'rgba(40, 167, 69, 0.7)',
                    'rgba(220, 53, 69, 0.7)'
                ],
                borderColor: '#ffffff',
                borderWidth: 2
            }]
        },
        options: {
            responsive: true,
            maintainAspectRatio: false,
        }
    });

    // --- INTERACTIVITY LOGIC ---
    const filterButtons = document.querySelectorAll('.filters button');

    function updateSalesChart(period) {
        salesChart.data.labels = salesData[period].labels;
        salesChart.data.datasets[0].data = salesData[period].data;
        salesChart.update();
    }

    filterButtons.forEach(button => {
        button.addEventListener('click', () => {
            // Remove 'active' class from all buttons
            filterButtons.forEach(btn => btn.classList.remove('active'));
            // Add 'active' class to the clicked button
            button.classList.add('active');

            // Update chart based on button id
            if (button.id === 'monthlyBtn') {
                updateSalesChart('monthly');
            } else if (button.id === 'quarterlyBtn') {
                updateSalesChart('quarterly');
            } else if (button.id === 'yearlyBtn') {
                updateSalesChart('yearly');
            }
        });
    });
});
